import { useState } from "react";

export default function NestedList() {
  const [data, setData] = useState([
    {
      type: "root",
      title: "Главный список",
      titleInput: "",
      fields: [
        { id: 1, value: "" },
      ],
      children: []
    }
  ]);

  // ------- вспомогательные функции -------
  function getNode(copy, path) {
    let node = copy;
    for (let index of path) {
      node = node[index];
    }
    return node;
  }

  function updateTitle(path, value) {
    setData(prev => {
      const copy = structuredClone(prev);
      const node = getNode(copy, path);
      if (node.type === "root") node.title = value;
      else node.titleInput = value;
      return copy;
    });
  }

  function updateField(path, index, value) {
    setData(prev => {
      const copy = structuredClone(prev);
      const node = getNode(copy, path);
      node.fields[index].value = value;
      return copy;
    });
  }

  function addField(path) {
    setData(prev => {
      const copy = structuredClone(prev);
      const node = getNode(copy, path);
      node.fields.push({
        id: Date.now(),
        value: ""
      });
      return copy;
    });
  }

  function removeField(path, index) {
    setData(prev => {
      const copy = structuredClone(prev);
      const node = getNode(copy, path);
      node.fields.splice(index, 1);
      return copy;
    });
  }

  function addChildList(path) {
    setData(prev => {
      const copy = structuredClone(prev);
      const node = getNode(copy, path);
      node.children.push({
        type: "child",
        title: "",
        titleInput: "",
        fields: [],
        children: []
      });
      return copy;
    });
  }

  // ------- рекурсивный компонент -------
  function RenderList({ node, path }) {
    return (
      <div
        style={{
          border: "1px solid #ccc",
          padding: "12px",
          marginTop: "12px",
          borderRadius: "6px",
          background: node.type === "root" ? "#f8f8f8" : "#fcfcfc"
        }}
      >
        {/* Название */}
        {node.type === "root" ? (
          <h2
            contentEditable
            suppressContentEditableWarning
            onBlur={(e) => updateTitle(path, e.target.innerText)}
            style={{ margin: 0, marginBottom: "10px" }}
          >
            {node.title}
          </h2>
        ) : (
          <input
            value={node.titleInput}
            placeholder="Название списка"
            onChange={(e) => updateTitle(path, e.target.value)}
            style={{
              padding: "6px",
              marginBottom: "10px",
              width: "100%",
              boxSizing: "border-box"
            }}
          />
        )}

        {/* Поля */}
        {node.fields.map((field, i) => (
          <div
            key={field.id}
            style={{
              display: "flex",
              alignItems: "center",
              marginBottom: "6px"
            }}
          >
            <input
              value={field.value}
              placeholder="Поле"
              onChange={(e) => updateField(path, i, e.target.value)}
              style={{
                padding: "6px",
                flex: 1,
                marginRight: "10px"
              }}
            />

            <span
              onClick={() => removeField(path, i)}
              style={{
                color: "red",
                cursor: "pointer",
                fontSize: "14px",
                userSelect: "none"
              }}
            >
              Удалить
            </span>
          </div>
        ))}

        <button onClick={() => addField(path)} style={{ marginTop: "6px" }}>
          Добавить поле
        </button>

        {/* Дочерние списки */}
        {node.children.map((child, i) => (
          <RenderList
            key={i}
            node={child}
            path={[...path, "children", i]}
          />
        ))}

        <button
          onClick={() => addChildList(path)}
          style={{ marginTop: "10px" }}
        >
          Добавить вложенный список
        </button>
      </div>
    );
  }

  // ------- основной рендер -------
  return (
    <div>
      {data.map((item, index) => (
        <RenderList key={index} node={item} path={[index]} />
      ))}
    </div>
  );
}
